ALGORITHM DigitalSignature
INPUT: message, signer's private key (d, n), verifier's public key (e, n)
OUTPUT: signature, verification result

// ========== SIGNING PHASE ==========
BEGIN GenerateSignature(message, d, n)
 // Step 1: Compute hash of the message
 hash = HASH(message)

 // Step 2: Sign the hash using private key (d, n)
 // signature = hash^d mod n (modular exponentiation)
 signature = MODULAR_EXPONENT(hash, d, n)

 RETURN signature
END

// ========== VERIFICATION PHASE ==========
BEGIN VerifySignature(message, signature, e, n)
 // Step 1: Compute hash of the received message
 hash_received = HASH(message)

 // Step 2: Verify signature using public key (e, n)
 // recovered_hash = signature^e mod n
 recovered_hash = MODULAR_EXPONENT(signature, e, n)

 // Step 3: Compare hashes
 IF hash_received == recovered_hash THEN
 RETURN TRUE // Signature is valid
 ELSE
 RETURN FALSE // Signature is invalid
 END IF
END

// ========== KEY PAIR GENERATION ==========
BEGIN GenerateKeyPair(p, q)
 // p, q: two large prime numbers
 n = p * q
 phi = (p - 1) * (q - 1)

 // Choose public exponent e (commonly 65537)
 e = 65537

 // Compute private exponent d (modular inverse of e mod phi)
 d = MODULAR_INVERSE(e, phi)

 // Public key: (e, n), Private key: (d, n)
 RETURN (e, n), (d, n)
END

ALGORITHM DiffieHellmanKeyExchange
INPUT: Public parameters - prime p, generator g
OUTPUT: Shared secret key between Alice and Bob

// ========== STEP 1: KEY GENERATION (Both Parties) ==========
BEGIN GenerateKeyPair(p, g)
 // Generate private key (random number less than p-1)
 private_key = RANDOM(1, p-1)

 // Compute public key: g^private_key mod p
 public_key = MODULAR_EXPONENT(g, private_key, p)

 RETURN private_key, public_key
END

// ========== STEP 2: KEY EXCHANGE ==========
// Alice has: private_A, public_B (received from Bob)
// Bob has: private_B, public_A (received from Alice)

BEGIN ComputeSharedSecret(private_key, other_public_key, p)
 // Shared secret = (other_public_key)^private_key mod p
 // = (g^other_private)^self_private mod p
 // = g^(other_private * self_private) mod p

 shared_secret = MODULAR_EXPONENT(other_public_key, private_key, p)
 RETURN shared_secret
END

// ========== COMPLETE PROTOCOL ==========
BEGIN Protocol()
 // Public parameters known to everyone
 p = LARGE_PRIME // e.g., 2^2048 - 1
 g = GENERATOR // e.g., 2

 // Alice generates her keys
 private_A, public_A = GenerateKeyPair(p, g)

 // Bob generates his keys
 private_B, public_B = GenerateKeyPair(p, g)

 // They exchange public keys over insecure channel
 // Alice receives public_B
 // Bob receives public_A

 // Both compute the SAME shared secret
 secret_A = ComputeSharedSecret(private_A, public_B, p)
 secret_B = ComputeSharedSecret(private_B, public_A, p)

 // secret_A == secret_B - this is the shared symmetric key
 RETURN secret_A
END

/*
 * Hybrid Encryption System Demonstration
 * Uses RSA for secure key exchange and AES for bulk data encryption
 * This is how real-world systems like PGP and SSL/TLS work
 */

#include <stdio.h>
#include <string.h>
#include <stdlib.h>

/* Simplified RSA structures for demonstration */
typedef struct {
 long e; /* Public exponent */
 long n; /* Modulus */
} PublicKey;

typedef struct {
 long d; /* Private exponent */
 long n; /* Modulus */
} PrivateKey;

/* Modular exponentiation: (base^exp) % mod */
long mod_pow(long base, long exp, long mod) {
 long result = 1;
 base = base % mod;

 while (exp > 0) {
 if (exp % 2 == 1) {
 result = (result * base) % mod;
 }
 exp = exp / 2;
 base = (base * base) % mod;
 }
 return result;
}

/* Extended Euclidean Algorithm for modular inverse */
long mod_inverse(long a, long m) {
 long m0 = m, t, q;
 long x0 = 0, x1 = 1;

 if (m == 1) return 0;

 while (a > 1) {
 q = a / m;
 t = m;
 m = a % m;
 a = t;
 t = x0;
 x0 = x1 - q * x0;
 x1 = t;
 }

 if (x1 < 0) x1 += m0;
 return x1;
}

/* Generate RSA key pair */
void generate_keys(PublicKey *pub, PrivateKey *priv, long p, long q) {
 long n = p * q;
 long phi = (p - 1) * (q - 1);
 long e = 65537; /* Common public exponent */
 long d = mod_inverse(e, phi);

 pub->e = e;
 pub->n = n;
 priv->d = d;
 priv->n = n;

 printf("Keys generated: n=%ld, e=%ld, d=%ld\n", n, e, d);
}

/* RSA Encryption (for small messages like AES keys) */
long rsa_encrypt(long message, PublicKey pub) {
 return mod_pow(message, pub.e, pub.n);
}

/* RSA Decryption */
long rsa_decrypt(long ciphertext, PrivateKey priv) {
 return mod_pow(ciphertext, priv.d, priv.n);
}

/* Simplified XOR encryption (simulating AES for demonstration) */
void xor_encrypt(char *data, char *key, int data_len, int key_len) {
 for (int i = 0; i < data_len; i++) {
 data[i] = data[i] ^ key[i % key_len];
 }
}

/* Generate a random session key */
void generate_session_key(char *key, int length) {
 for (int i = 0; i < length; i++) {
 key[i] = rand() % 256;
 }
}

/* ==================== MAIN DEMONSTRATION ==================== */
int main() {
 printf("============================================================\n");
 printf(" HYBRID ENCRYPTION SYSTEM (RSA + Symmetric)\n");
 printf("============================================================\n\n");

 /* Step 1: Generate RSA key pair for recipient (Bob) */
 printf("STEP 1: Bob generates RSA key pair\n");
 printf("-----------------------------------\n");

 PublicKey bob_public;
 PrivateKey bob_private;

 /* Use small primes for demonstration */
 generate_keys(&bob_public, &bob_private, 61, 53);

 /* Bob shares his public key with everyone */
 printf("Bob's Public Key (e, n): (%ld, %ld)\n", bob_public.e, bob_public.n);
 printf("Bob keeps Private Key secret\n\n");

 /* Step 2: Alice wants to send a large message to Bob */
 printf("STEP 2: Alice sends message to Bob\n");
 printf("-----------------------------------\n");

 char plaintext[] = "Secret message for Bob!";
 int msg_len = strlen(plaintext);

 printf("Alice's message: \"%s\"\n", plaintext);
 printf("Message length: %d bytes\n\n", msg_len);

 /* Step 3: Alice generates a random session key (for symmetric encryption) */
 printf("STEP 3: Alice generates random session key\n");
 printf("--------------------------------------------\n");

 char session_key[8] = {0};
 srand(12345); /* Fixed seed for reproducibility */
 generate_session_key(session_key, 8);

 printf("Session Key: ");
 for (int i = 0; i < 8; i++) printf("%02x", (unsigned char)session_key[i]);
 printf("\n");
 printf("(This key will encrypt the actual message)\n\n");

 /* Step 4: Alice encrypts session key with Bob's public key */
 printf("STEP 4: Alice encrypts session key with RSA\n");
 printf("----------------------------------------------\n");

 /* Convert session key to integer (simplified) */
 long session_key_int = 0;
 for (int i = 0; i < 4; i++) {
 session_key_int = (session_key_int << 8) | (unsigned char)session_key[i];
 }

 long encrypted_key = rsa_encrypt(session_key_int, bob_public);
 printf("Encrypted Session Key: %ld\n", encrypted_key);
 printf("(Only Bob's private key can decrypt this!)\n\n");

 /* Step 5: Alice encrypts message with session key (symmetric encryption) */
 printf("STEP 5: Alice encrypts message with session key\n");
 printf("----------------------------------------------------\n");

 char encrypted_msg[100];
 strcpy(encrypted_msg, plaintext);
 xor_encrypt(encrypted_msg, session_key, msg_len, 8);

 printf("Encrypted Message (hex): ");
 for (int i = 0; i < msg_len; i++) printf("%02x", (unsigned char)encrypted_msg[i]);
 printf("\n\n");

 /* Step 6: Bob decrypts the session key */
 printf("STEP 6: Bob decrypts the session key\n");
 printf("------------------------------------\n");

 long decrypted_key_int = rsa_decrypt(encrypted_key, bob_private);

 char decrypted_key[8] = {0};
 for (int i = 3; i >= 0; i--) {
 decrypted_key[i] = decrypted_key_int & 0xFF;
 decrypted_key_int >>= 8;
 }

 printf("Decrypted Session Key: ");
 for (int i = 0; i < 8; i++) printf("%02x", (unsigned char)decrypted_key[i]);
 printf("\n\n");

 /* Step 7: Bob decrypts the message */
 printf("STEP 7: Bob decrypts the message\n");
 printf("---------------------------------\n");

 xor_encrypt(encrypted_msg, decrypted_key, msg_len, 8);

 printf("Decrypted Message: \"%s\"\n", encrypted_msg);
 printf("Message successfully recovered!\n");

 printf("\n============================================================\n");
 printf(" SUMMARY: WHY HYBRID ENCRYPTION?\n");
 printf("============================================================\n");
 printf("1. RSA encrypts the SESSION KEY (small data)\n");
 printf("2. Symmetric encryption (AES) encrypts the MESSAGE (large data)\n");
 printf("3. Combines benefits of both: secure key exchange + fast encryption\n");
 printf("4. Used in: PGP, S/MIME, SSL/TLS, HTTPS\n");

 return 0;
}
